from collections import Counter

class Solution:
    def minLengthAfterRemovals(self, nums):
        n = len(nums)
        counts = Counter(nums)
        max_freq = max(counts.values())
        if max_freq * 2 <= n:
            return n % 2
        return max_freq * 2 - n

