var minLengthAfterRemovals = function(nums) {
    const n = nums.length;
    const counts = new Map();
    let maxFreq = 0;
    for (const v of nums) {
        const c = (counts.get(v) || 0) + 1;
        counts.set(v, c);
        if (c > maxFreq) maxFreq = c;
    }
    if (maxFreq * 2 <= n) return n % 2;
    return maxFreq * 2 - n;
};
